class SemanticVersion implements Comparable<SemanticVersion> {
  final int major;
  final int minor;
  final int patch;
  final List<String> prerelease;
  final String buildMetadata;

  SemanticVersion(
    this.major,
    this.minor,
    this.patch,
    Iterable<String> prerelease,
    this.buildMetadata,
  ) : prerelease = List<String>.unmodifiable(prerelease);

  factory SemanticVersion.parse(String source) {
    final match = RegExp(
      r'^(\d+)\.(\d+)\.(\d+)(?:-([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?(?:\+([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?$',
    ).firstMatch(source);
    if (match == null) {
      throw FormatException('invalid semantic version', source);
    }
    return SemanticVersion(
      int.parse(match.group(1)!),
      int.parse(match.group(2)!),
      int.parse(match.group(3)!),
      match.group(4)?.split('.') ?? const <String>[],
      match.group(5) ?? '',
    );
  }

  @override
  int compareTo(SemanticVersion other) {
    var comparison = major.compareTo(other.major);
    if (comparison != 0) return comparison;
    comparison = minor.compareTo(other.minor);
    if (comparison != 0) return comparison;
    comparison = patch.compareTo(other.patch);
    if (comparison != 0) return comparison;
    return prerelease.join('.').compareTo(other.prerelease.join('.'));
  }

  @override
  String toString() {
    final prereleaseSuffix = prerelease.isEmpty
        ? ''
        : '-${prerelease.join('.')}';
    final buildSuffix = buildMetadata.isEmpty ? '' : '+$buildMetadata';
    return '$major.$minor.$patch$prereleaseSuffix$buildSuffix';
  }
}

