import 'package_release.dart';
import 'semantic_version.dart';

class ReleaseSelector {
  PackageRelease? bestCompatible(
    Iterable<PackageRelease> releases,
    String constraint,
  ) {
    final clauses = constraint
        .trim()
        .split(RegExp(r'\s+'))
        .where((clause) => clause.isNotEmpty)
        .toList(growable: false);
    if (clauses.isEmpty) {
      throw ArgumentError.value(constraint, 'constraint', 'must not be empty');
    }

    final candidates = releases
        .where((release) => !release.withdrawn)
        .where(
          (release) =>
              clauses.any((clause) => _matches(release.version, clause)),
        )
        .toList();
    candidates.sort((left, right) => left.version.compareTo(right.version));
    return candidates.isEmpty ? null : candidates.last;
  }

  bool _matches(SemanticVersion version, String clause) {
    final match = RegExp(r'^(>=|<=|>|<|=)(.+)$').firstMatch(clause);
    if (match == null) {
      throw FormatException('invalid version clause', clause);
    }
    final comparison = version.compareTo(
      SemanticVersion.parse(match.group(2)!),
    );
    final operator = match.group(1)!;
    if (operator == '>=') return comparison >= 0;
    if (operator == '<=') return comparison <= 0;
    if (operator == '>') return comparison > 0;
    if (operator == '<') return comparison < 0;
    return comparison == 0;
  }
}

