import '../lib/package_release.dart';
import '../lib/release_selector.dart';
import '../lib/semantic_version.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

PackageRelease release(String version, {bool withdrawn = false}) {
  return PackageRelease.fromText('renderer', version, withdrawn: withdrawn);
}

void main() {
  check(
    SemanticVersion.parse('1.10.0').compareTo(SemanticVersion.parse('1.2.0')) >
        0,
    'orders stable versions by numeric core',
  );

  final selected = ReleaseSelector().bestCompatible(<PackageRelease>[
    release('0.9.0'),
    release('1.3.0'),
    release('1.4.0', withdrawn: true),
  ], '>=1.0.0');
  check(
    selected?.version.toString() == '1.3.0',
    'selects the best active release',
  );

  print('public tests passed');
}
